concepts.solution:
function evaluate(input: { required: string[]; reward: string }, state: { flags: string[]; rewards: string[] }): boolean {
  const hasRequirements = input.required.every((flag) => state.flags.includes(flag));
  if (!hasRequirements) return false;
  if (!state.rewards.includes(input.reward)) {
    state.rewards.push(input.reward);
  }
  return true;
}

