  for (const flag of input.flags) {
    if (!state.flags.includes(flag)) return false;
  }
  return true;
}

concepts.solution:
function evaluate(input: { options: Array<{ id: string; weight: number }>; roll: number }, state: unknown): string | null {
  let total = 0;
  for (const option of input.options) {
    total += option.weight;
    if (input.roll < total) return option.id;
  }
  return input.options.length ? input.options[input.options.length - 1].id : null;
}

